// Parse Extracted Data2
// Input: GPT-4o response — with simplifyOutput ON, the text is at $json.message.content
// Falls back to choices[0].message.content for safety.

const gptOutput = $input.item.json;

const rawContent =
  gptOutput?.message?.content ||
  gptOutput?.choices?.[0]?.message?.content ||
  gptOutput?.text ||
  '';

if (!rawContent) {
  throw new Error(
    'GPT-4o returned empty content. Keys found: ' + Object.keys(gptOutput).join(', ')
  );
}

let parsed;
try {
  parsed = JSON.parse(rawContent);
} catch (e) {
  const clean = rawContent.replace(/```json|```/g, '').trim();
  try {
    parsed = JSON.parse(clean);
  } catch (e2) {
    throw new Error('Failed to parse GPT JSON response: ' + rawContent.substring(0, 400));
  }
}

if (!parsed.drugs || !Array.isArray(parsed.drugs)) {
  throw new Error('GPT did not return a valid drugs array. Response: ' + JSON.stringify(parsed).substring(0, 300));
}

const drugNames = parsed.drugs
  .map(d => (d.generic_name || d.name || '').toLowerCase().trim())
  .filter(Boolean);

return {
  ...parsed,
  drug_names_flat: drugNames.join(','),
  drug_list: drugNames,
  source_file_id: $('Download PDF from Drive').item.json.id,
  source_file_name: $('Watch Prescriptions Folder').item.json.name,
  extracted_at: new Date().toISOString()
};

