const prescription = $('Parse & Validate GPT Response').item.json;
const drugList = prescription.drug_list || [];

const formularyRows   = $('Read Approved Drug Formulary').all().map(i => i.json);
const interactionRows = $('Read Drug Interactions Table').all().map(i => i.json);

// Formulary check
const formularyDrugs = formularyRows.map(r =>
  (r['drug_name'] || r['Drug Name'] || '').toLowerCase().trim()
);
const notInFormulary = drugList.filter(d =>
  !formularyDrugs.some(f => f.includes(d) || d.includes(f))
);

// Interaction check
const interactions = [];
for (const row of interactionRows) {
  const drugA       = (row['drug_a']         || row['Drug A']       || '').toLowerCase().trim();
  const drugB       = (row['drug_b']         || row['Drug B']       || '').toLowerCase().trim();
  const severity    =  row['severity']       || row['Severity']      || 'Unknown';
  const description =  row['description']    || row['Description']   || '';
  const action      =  row['clinical_action'] || '';

  const aPresent = drugList.some(d => d.includes(drugA) || drugA.includes(d));
  const bPresent = drugList.some(d => d.includes(drugB) || drugB.includes(d));

  if (aPresent && bPresent) {
    interactions.push({ drugA, drugB, severity, description, action });
  }
}

const hasInteractions    = interactions.length > 0;
const hasFormularyIssues = notInFormulary.length > 0;
const needsAlert         = hasInteractions || hasFormularyIssues;

return {
  ...prescription,
  interactions,
  not_in_formulary: notInFormulary,
  has_interactions: hasInteractions,
  has_formulary_issues: hasFormularyIssues,
  needs_pharmacist_alert: needsAlert,
  check_timestamp: new Date().toISOString()
};

